134	            </div>
135	          )}
136	
137	          {context.map((c, idx) => (
138	            <ContextRow
139	              key={idx}
140	              assignment={c}
141	              otherMarkets={otherMarkets}
142	              onUpdate={(field, value) => updateContext(idx, field, value)}
143	              onRemove={() => removeContext(idx)}
144	            />
145	          ))}
146	        </div>
147	
148	        <button
149	          type="submit"
150	          disabled={mutation.isPending}
151	          style={{
152	            padding: "8px 16px",
153	            borderRadius: "var(--radius-sm)",
154	            border: "none",
155	            background: hasContext ? "var(--color-info)" : "var(--color-primary)",
156	            color: "#fff",
157	            fontWeight: 600,
158	            cursor: mutation.isPending ? "not-allowed" : "pointer",
159	            opacity: mutation.isPending ? 0.6 : 1,
